-- Validate plugin code for dangerous patterns
local function validate_plugin_code(code)
    if not code or type(code) ~= "string" or #code == 0 then
        return false, "empty or invalid plugin code"
    end

    if #code > 65536 then
        return false, "plugin code exceeds maximum size (64KB)"
    end

    local dangerous_patterns = {
        { pattern = "os%.", msg = "os module access not allowed" },
        { pattern = "io%.", msg = "io module access not allowed" },
        { pattern = "loadfile", msg = "loadfile not allowed" },
        { pattern = "dofile", msg = "dofile not allowed" },
        { pattern = "require%s*%(?%s*['\"]ffi", msg = "ffi module not allowed" },
        { pattern = "rawset", msg = "rawset not allowed" },
        { pattern = "rawget", msg = "rawget not allowed" },
        { pattern = "setmetatable", msg = "setmetatable not allowed in plugins" },
        { pattern = "getmetatable", msg = "getmetatable not allowed in plugins" },
        { pattern = "debug%.", msg = "debug module not allowed" },
        { pattern = "package%.", msg = "package module not allowed" },
        { pattern = "collectgarbage", msg = "collectgarbage not allowed" },
        { pattern = "newproxy", msg = "newproxy not allowed" },
        { pattern = "setfenv", msg = "setfenv not allowed" },
        { pattern = "getfenv", msg = "getfenv not allowed" },
        { pattern = "module%s*%(", msg = "module() not allowed" },
        { pattern = "coroutine%.", msg = "coroutine access not allowed" },
    }

    for _, check in ipairs(dangerous_patterns) do
        if string.find(code, check.pattern) then
            return false, check.msg
        end
    end

    return true, nil
end

-- Compile and cache plugin code
local function compile_plugin(name, code)
    local ok, err = validate_plugin_code(code)
    if not ok then
        return nil, "validation failed: " .. err
    end

    local load_fn = load or loadstring
    local chunk, compile_err = load_fn(code, "plugin:" .. name)
    if not chunk then
        return nil, "compilation failed: " .. compile_err
    end

    return chunk, nil
end

-- Get Redis connection
local function get_redis_connection()
    local red = redis:new()
    red:set_timeout(REDIS_TIMEOUT)

    local ok, err = red:connect(REDIS_HOST, REDIS_PORT)
    if not ok then
        return nil, "redis connect failed: " .. (err or "unknown")
    end

    if REDIS_PASSWORD then
        local res, auth_err = red:auth(REDIS_PASSWORD)
        if not res then
            return nil, "redis auth failed: " .. (auth_err or "unknown")
        end
    end

    return red, nil
end

-- Return Redis connection to pool
local function release_redis_connection(red)
    if red then
        red:set_keepalive(REDIS_KEEPALIVE_TIMEOUT, REDIS_POOL_SIZE)
    end
end

-- Load plugin from Redis
function _M.load_plugin_from_redis(plugin_name)
    if not plugin_name or plugin_name == "" then
        return nil, "plugin name is required"
    end

    -- Check worker-level cache first
    local now = ngx.time()
    if worker_cache[plugin_name] and worker_cache_ttl[plugin_name] and worker_cache_ttl[plugin_name] > now then
        return worker_cache[plugin_name], nil
    end

    -- Check shared dict cache
    local cached_code = plugin_cache and plugin_cache:get(plugin_name)
    if cached_code then
        local chunk, err = compile_plugin(plugin_name, cached_code)
        if chunk then
            worker_cache[plugin_name] = chunk
            worker_cache_ttl[plugin_name] = now + CACHE_TTL
            return chunk, nil
        end
        return nil, err
    end

    -- Load from Redis
    local red, redis_err = get_redis_connection()
    if not red then
        return nil, redis_err
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    local code, err = red:get(key)
    release_redis_connection(red)

    if not code or code == ngx.null then
        return nil, "plugin '" .. plugin_name .. "' not found in Redis"
    end

    -- Compile plugin
    local chunk, compile_err = compile_plugin(plugin_name, code)
    if not chunk then
        return nil, compile_err
    end

    -- Store in shared dict cache
    if plugin_cache then
        plugin_cache:set(plugin_name, code, CACHE_TTL)
    end

    -- Store in worker cache
    worker_cache[plugin_name] = chunk
    worker_cache_ttl[plugin_name] = now + CACHE_TTL

    ngx.log(ngx.INFO, "plugin '", plugin_name, "' loaded from Redis successfully")
    return chunk, nil
end

-- Load plugin from HTTP header
function _M.load_plugin_from_header(header_name)
