-- Load plugin from request body (JSON payload)
function _M.load_plugin_from_body()
    ngx.req.read_body()
    local body = ngx.req.get_body_data()
    if not body then
        return nil, "empty request body"
    end

    local payload, decode_err = cjson.decode(body)
    if not payload then
        return nil, "invalid JSON body: " .. (decode_err or "unknown")
    end

    local plugin_name = payload.name or "unnamed_plugin"
    local code = payload.code

    if not code then
        return nil, "missing 'code' field in JSON body"
    end

    -- Support base64 encoded code
    if payload.encoding == "base64" then
        local decoded = ngx.decode_base64(code)
        if not decoded then
            return nil, "failed to decode base64 plugin code"
        end
        code = decoded
    end

    local chunk, err = compile_plugin(plugin_name, code)
    if not chunk then
        return nil, err
    end

    ngx.log(ngx.INFO, "plugin '", plugin_name, "' loaded from request body successfully")
    return chunk, nil
end

-- Execute a compiled plugin chunk safely within sandbox
function _M.execute_plugin(chunk, context)
    if not chunk then
        return nil, "no plugin chunk provided"
    end

    local sandbox = create_sandbox()

    -- Merge context into sandbox
    if context and type(context) == "table" then
        sandbox.ctx = context
    end

    -- Set sandbox environment
    if setfenv then
        -- Lua 5.1 / LuaJIT
        setfenv(chunk, sandbox)
    end

    -- Execute with timeout protection
    local ok, result = pcall(chunk)
    if not ok then
        ngx.log(ngx.ERR, "plugin execution error: ", tostring(result))
        return nil, "execution error: " .. tostring(result)
    end

    -- If the plugin returns a function or table, set its environment too
    if type(result) == "function" then
        if setfenv then
            setfenv(result, sandbox)
        end
    end

    return result, nil
end

-- Register a plugin to Redis
function _M.register_plugin(plugin_name, code, metadata)
    if not plugin_name or plugin_name == "" then
        return false, "plugin name is required"
    end

    local ok, err = validate_plugin_code(code)
    if not ok then
        return false, "validation failed: " .. err
    end

    -- Test compilation
    local chunk, compile_err = compile_plugin(plugin_name, code)
    if not chunk then
        return false, compile_err
    end

    local red, redis_err = get_redis_connection()
    if not red then
        return false, redis_err
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name

    -- Store code
    local set_ok, set_err = red:set(key, code)
    if not set_ok then
        release_redis_connection(red)
        return false, "failed to store plugin: " .. (set_err or "unknown")
    end

    -- Store metadata if provided
    if metadata and type(metadata) == "table" then
        local meta_key = key .. ":meta"
        local meta_json = cjson.encode(metadata)
        if meta_json then
            red:set(meta_key, meta_json)
        end
    end

    -- Register plugin name in the set of all plugins
    red:sadd(REDIS_PLUGIN_PREFIX .. "all", plugin_name)

    release_redis_connection(red)

    -- Invalidate caches
    if plugin_cache then
        plugin_cache:delete(plugin_name)
    end
    worker_cache[plugin_name] = nil
    worker_cache_ttl[plugin_name] = nil

    ngx.log(ngx.INFO, "plugin '", plugin_name, "' registered successfully")
    return true, nil
end

-- Remove a plugin from Redis
function _M.unregister_plugin(plugin_name)
    if not plugin_name or plugin_name == "" then
        return false, "plugin name is required"
    end

    local red, redis_err = get_redis_connection()
    if not red then
        return false, redis_err
    end

    local key = REDIS_PLUGIN_PREFIX .. plugin_name
    red:del(key)
    red:del(key .. ":meta")
    red:srem(REDIS_PLUGIN_PREFIX .. "all", plugin_name)

    release_redis_connection(red)

    -- Invalidate caches
    if plugin_cache then
        plugin_cache:delete(plugin_name)
    end
    worker_cache[plugin_name] = nil
    worker_cache_ttl[plugin_name] = nil

    ngx.log(ngx.INFO, "plugin '", plugin_name, "' unregistered successfully")
    return true, nil
end

-- List all registered plugins
function _M.list_plugins()
    local red, redis_err = get_redis_connection()
    if not red then
        return nil, redis_err
    end

    local plugins, err = red:smembers(REDIS_PLUGIN_PREFIX .. "all")
    release_redis_connection(red)

    if not plugins or plugins == ngx.null then
        return {}, nil
    end

    return plugins, nil
end

-- Get plugin metadata
function _M.get_plugin_metadata(plugin_name)
    local red, redis_err = get_redis_connection()
    if not red then
        return nil, redis_err
    end

    local meta_key = REDIS_PLUGIN_PREFIX .. plugin_name .. ":meta"
    local meta_json, err = red:get(meta_key)
    release_redis_connection(red)

    if not meta_json or meta_json == ngx.null then
        return nil, "metadata not found"
    end

    local metadata, decode_err = cjson.decode(meta_json)
    if not metadata then
        return nil, "invalid metadata JSON: " .. (decode_err or "unknown")
    end

    return metadata, nil
end

-- Plugin chain executor - runs a sequence of plugins
function _M.execute_plugin_chain(plugin_names, context)
    if not plugin_names or type(plugin_names) ~= "table" or #plugin_names == 0 then
        return true, nil
    end

    context = context or {}
    context.chain_index = 0
    context.chain_length = #plugin_names
    context.chain_aborted = false

    for i, name in ipairs(plugin_names) do
        context.chain_index = i

        local chunk, load_err = _M.load_plugin_from_redis(name)
        if not chunk then
            ngx.log(ngx.ERR, "failed to load plugin '", name, "' in chain: ", load_err)
            return false, "chain halted at plugin '" .. name .. "': " .. load_err
        end

        local result, exec_err = _M.execute_plugin(chunk, context)
        if exec_err then
            ngx.log(ngx.ERR, "plugin '", name, "' failed in chain: ", exec_err)
            return false, "chain halted at plugin '" .. name .. "': " .. exec_err
        end

        -- If plugin returns a table with handler functions, call the appropriate phase handler
        if type(result) == "table" then
            local phase = context.phase or "access"
            local handler = result[phase]
            if handler and type(handler) == "function" then
                local handler_ok, handler_err = pcall(handler, context)
                if not handler_ok then
                    ngx.log(ngx.ERR, "plugin '", name, "' handler failed: ", tostring(handler_err))
                    return false, "chain halted at plugin '" .. name .. "': " .. tostring(handler_err)
                end
            end
        end

        -- Check if plugin aborted the chain
        if context.chain_aborted then
            ngx.log(ngx.INFO, "plugin chain aborted by plugin '", name, "'")
            return true, "chain aborted by plugin '" .. name .. "'"
        end
    end

    return true, nil
end

-- Invalidate cache for a specific plugin or all plugins
function _M.invalidate_cache(plugin_name)
    if plugin_name then
        if plugin_cache then
            plugin_cache:delete(plugin_name)
        end
        worker_cache[plugin_name] = nil
        worker_cache_ttl[plugin_name] = nil
        ngx.log(ngx.INFO, "cache invalidated for plugin '", plugin_name, "'")
    else
        if plugin_cache then
            plugin_cache:flush_all()
        end
        worker_cache = {}
        worker_cache_ttl = {}
        ngx.log(ngx.INFO, "all plugin caches invalidated")
    end
    return true
end

-- HTTP API handler for plugin management
function _M.api_handler()
    local method = ngx.req.get_method()
    local uri_args = ngx.req.get_uri_args()
    local plugin_name = uri_args.name

    ngx.header["Content-Type"] = "application/json"

    -- GET /plugins - List all plugins or get specific plugin info
    if method == "GET" then
        if plugin_name then
            local meta, err = _M.get_plugin_metadata(plugin_name)
            local response = {
                name = plugin_name,
                metadata = meta,
            }
            ngx.say(cjson.encode(response))
        else
            local plugins, err = _M.list_plugins()
            if not plugins then
                ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                ngx.say(cjson.encode({ error = err }))
                return
            end
            ngx.say(cjson.encode({ plugins = plugins }))
        end

    -- POST /plugins - Register a new plugin
    elseif method == "POST" then
        ngx.req.read_body()
        local body = ngx.req.get_body_data()
        if not body then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "empty request body" }))
            return
        end

        local payload, decode_err = cjson.decode(body)
        if not payload then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "invalid JSON: " .. (decode_err or "unknown") }))
            return
        end

        local name = payload.name
        local code = payload.code
        local metadata = payload.metadata

        if not name or not code then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "'name' and 'code' are required" }))
            return
        end

        -- Support base64 encoded code
        if payload.encoding == "base64" then
            local decoded = ngx.decode_base64(code)
            if not decoded then
                ngx.status = ngx.HTTP_BAD_REQUEST
                ngx.say(cjson.encode({ error = "failed to decode base64 code" }))
                return
            end
            code = decoded
        end

        local ok, err = _M.register_plugin(name, code, metadata)
        if not ok then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = err }))
            return
        end

        ngx.status = 201
        ngx.say(cjson.encode({ status = "registered", name = name }))

    -- DELETE /plugins?name=xxx - Remove a plugin
    elseif method == "DELETE" then
        if not plugin_name then
            ngx.status = ngx.HTTP_BAD_REQUEST
            ngx.say(cjson.encode({ error = "'name' parameter is required" }))
            return
        end

        local ok, err = _M.unregister_plugin(plugin_name)
        if not ok then
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = err }))
            return
        end

        ngx.say(cjson.encode({ status = "unregistered", name = plugin_name }))

    -- PUT /plugins/execute - Execute a plugin by name or from body
    elseif method == "PUT" then
        local context = {
            request_uri = ngx.var.request_uri,
            remote_addr = ngx.var.remote_addr,
            uri_args = uri_args,
            phase = "access",
        }

        -- Execute from plugin name
        if plugin_name then
            local chunk, load_err = _M.load_plugin_from_redis(plugin_name)
            if not chunk then
                ngx.status = ngx.HTTP_NOT_FOUND
                ngx.say(cjson.encode({ error = load_err }))
                return
            end

            local result, exec_err = _M.execute_plugin(chunk, context)
            if exec_err then
                ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                ngx.say(cjson.encode({ error = exec_err }))
                return
            end

            ngx.say(cjson.encode({ status = "executed", name = plugin_name, result = tostring(result) }))

        -- Execute from request body
        else
            local chunk, load_err = _M.load_plugin_from_body()
            if not chunk then
                ngx.status = ngx.HTTP_BAD_REQUEST
                ngx.say(cjson.encode({ error = load_err }))
                return
            end

            local result, exec_err = _M.execute_plugin(chunk, context)
            if exec_err then
                ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                ngx.say(cjson.encode({ error = exec_err }))
                return
            end

            ngx.say(cjson.encode({ status = "executed", result = tostring(result) }))
        end

    -- PATCH /plugins/cache?name=xxx - Invalidate cache
    elseif method == "PATCH" then
        _M.invalidate_cache(plugin_name)
        ngx.say(cjson.encode({ status = "cache_invalidated", name = plugin_name or "all" }))

    else
        ngx.status = 405
        ngx.say(cjson.encode({ error = "method not allowed" }))
    end
end

-- Access phase handler - loads and executes plugins for incoming requests
function _M.access_phase_handler()
    -- Get plugin chain from request header or route configuration
    local plugin_header = ngx.req.get_headers()["X-Gateway-Plugins"]
    local plugin_names = {}

    if plugin_header then
        -- Parse comma-separated plugin names
        for name in string.gmatch(plugin_header, "([^,]+)") do
            name = name:match("^%s*(.-)%s*$") -- trim whitespace
            if name ~= "" then
                table.insert(plugin_names, name)
            end
        end
    end

    -- Also check for inline plugin code in header
    local inline_code_header = ngx.req.get_headers()["X-Gateway-Plugin-Code"]
    if inline_code_header then
        local chunk, err = _M.load_plugin_from_header("X-Gateway-Plugin-Code")
        if chunk then
            local context = {
                request_uri = ngx.var.request_uri,
                remote_addr = ngx.var.remote_addr,
                method = ngx.req.get_method(),
                headers = ngx.req.get_headers(),
                uri_args = ngx.req.get_uri_args(),
                phase = "access",
            }
            local result, exec_err = _M.execute_plugin(chunk, context)
            if exec_err then
                ngx.log(ngx.ERR, "inline plugin execution error: ", exec_err)
                ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
                ngx.say(cjson.encode({ error = "plugin execution failed" }))
                return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
            end
        else
            ngx.log(ngx.WARN, "failed to load inline plugin: ", err)
        end
    end

    -- Execute plugin chain from Redis
    if #plugin_names > 0 then
        local context = {
            request_uri = ngx.var.request_uri,
            remote_addr = ngx.var.remote_addr,
            method = ngx.req.get_method(),
            headers = ngx.req.get_headers(),
            uri_args = ngx.req.get_uri_args(),
            phase = "access",
        }

        local ok, chain_err = _M.execute_plugin_chain(plugin_names, context)
        if not ok then
            ngx.log(ngx.ERR, "plugin chain error: ", chain_err)
            ngx.status = ngx.HTTP_INTERNAL_SERVER_ERROR
            ngx.say(cjson.encode({ error = "plugin chain execution failed", detail = chain_err }))
            return ngx.exit(ngx.HTTP_INTERNAL_SERVER_ERROR)
        end
    end
end

-- Health check endpoint
function _M.health_check()
    ngx.header["Content-Type"] = "application/json"

    local health = {
        status = "ok",
        worker_cached_plugins = 0,
        redis_connected = false,
    }

    -- Count worker cached plugins
    for _ in pairs(worker_cache) do
        health.worker_cached_plugins = health.worker_cached_plugins + 1
    end

    -- Check Redis connectivity
    local red, err = get_redis_connection()
    if red then
        health.redis_connected = true
        local info = red:ping()
        health.redis_ping = (info == "PONG")
        release_redis_connection(red)
    else
        health.redis_error = err
    end

    -- Check shared dict
    if plugin_cache then
        health.shared_cache_free = plugin_cache:free_space()
    end

    ngx.say(cjson.encode(health))
end

return _M